/**
 * Operations Dashboard — System health, metrics, alerts, incidents.
 * OBSERVABILITY ONLY — no trading execution.
 */
import { useState, useEffect, useCallback } from 'react';
import { api } from '../utils/api';
import { tokens } from '../styles/tokens';
import GlassPanel from '../components/ui/GlassPanel';
import StatCard from '../components/ui/StatCard';
import usePageTitle from '../hooks/usePageTitle';
import s from './OperationsDashboardPage.module.css';

const T = { bg: tokens.color.bg, surface: tokens.color.surface, surface2: tokens.color.surfaceHover, border: tokens.color.border, text: tokens.color.text, textSec: tokens.color.textSecondary, green: tokens.color.green, red: tokens.color.red, blue: tokens.color.blue, amber: tokens.color.amber, purple: tokens.color.purple, mono: tokens.font.mono };
const SC = { healthy: T.green, warning: T.amber, critical: T.red, unknown: T.textSec };

export default function OperationsDashboardPage() {
  usePageTitle('Operations');
  const [health, setHealth] = useState(null);
  const [metrics, setMetrics] = useState(null);
  const [alerts, setAlerts] = useState([]);
  const [alertStats, setAlertStats] = useState(null);
  const [incidents, setIncidents] = useState([]);
  const [diagnostics, setDiagnostics] = useState(null);
  const [loading, setLoading] = useState(true);

  const fetchAll = useCallback(async () => {
    const [h, m, a, i, d] = await Promise.all([
      api('/api/ops/health'),
      api('/api/ops/metrics'),
      api('/api/ops/alerts?limit=15'),
      api('/api/ops/incidents?limit=10'),
      api('/api/ops/diagnostics'),
    ]);
    if (h) setHealth(h);
    if (m) setMetrics(m);
    if (a) { setAlerts(a.alerts || []); setAlertStats(a.stats || null); }
    if (i) setIncidents(i.incidents || []);
    if (d) setDiagnostics(d);
    setLoading(false);
  }, []);

  useEffect(() => { fetchAll(); }, [fetchAll]);
  useEffect(() => { const iv = setInterval(fetchAll, 30000); return () => clearInterval(iv); }, [fetchAll]);

  if (loading) return <div className={s.loading}>Loading operations...</div>;

  const overall = health?.overall_status || 'unknown';
  const apiM = metrics?.api || {};
  const wg = metrics?.worker_grid || {};

  return (
    <div className={s.page}>
      <div className={s.header}>
        <div>
          <h1 className={s.headerTitle}>Platform Operations</h1>
          <p className={s.headerSubtitle}>Observability and diagnostics — no trading execution</p>
        </div>
        <div className={s.statusRow}>
          <span className={s.statusDot} style={{ background: SC[overall], boxShadow: `0 0 8px ${SC[overall]}` }} />
          <span className={s.statusLabel} style={{ color: SC[overall] }}>{overall.toUpperCase()}</span>
        </div>
      </div>

      {/* Summary Stats */}
      <div className={s.statsGrid}>
        <StatCard label="Healthy" value={health?.healthy || 0} accentColor={T.green} compact />
        <StatCard label="Warnings" value={health?.warnings || 0} accentColor={T.amber} compact />
        <StatCard label="Critical" value={health?.critical || 0} accentColor={T.red} compact />
        <StatCard label="API Requests" value={apiM.requests || 0} accentColor={T.blue} compact />
        <StatCard label="Error Rate" value={`${apiM.error_rate || 0}%`} accentColor={apiM.error_rate > 5 ? T.red : T.green} compact />
        <StatCard label="P95 Latency" value={`${apiM.latency_p95 || 0}ms`} accentColor={T.blue} compact />
        <StatCard label="Workers" value={wg.active_workers || 0} accentColor={T.green} compact />
        <StatCard label="Queue" value={wg.queue_depth || 0} accentColor={wg.queue_depth > 500 ? T.amber : T.blue} compact />
      </div>

      <div className={s.twoColGrid}>
        {/* Health Checks */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>HEALTH CHECKS</h3>
          {(health?.checks || []).map(c => (
            <div key={c.component} className={s.checkRow}>
              <div className={s.checkRowLeft}>
                <span className={s.checkDot} style={{ background: SC[c.status] || T.textSec }} />
                <span className={s.checkName}>{c.component}</span>
              </div>
              <span className={s.checkDetails}>{c.details}</span>
            </div>
          ))}
        </GlassPanel>

        {/* Alerts */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>
            ALERTS ({alertStats?.unacknowledged || 0} unacked)
          </h3>
          {alerts.length === 0 ? (
            <div className={s.emptyState}>No alerts</div>
          ) : alerts.slice(0, 8).map(a => (
            <div key={a.alert_id} className={s.alertItem} style={{ borderLeft: `3px solid ${SC[a.severity] || T.textSec}` }}>
              <div className={s.alertTitle}>{a.title}</div>
              <div className={s.alertMeta}>{a.source} · {(a.timestamp || '').slice(11, 19)}</div>
            </div>
          ))}
        </GlassPanel>
      </div>

      <div className={s.twoColGrid}>
        {/* Diagnostics */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>DIAGNOSTICS</h3>
          {diagnostics?.risk_flags?.length > 0 && (
            <div className={s.riskFlagsBox} style={{ background: T.red + '11' }}>
              {diagnostics.risk_flags.map((f, i) => (
                <div key={i} className={s.riskFlag}>{f}</div>
              ))}
            </div>
          )}
          {(diagnostics?.findings || []).map((f, i) => (
            <div key={i} className={s.finding}>{f}</div>
          ))}
          {(diagnostics?.recommendations || []).map((r, i) => (
            <div key={i} className={s.recommendation}>{r.priority}: {r.action}</div>
          ))}
        </GlassPanel>

        {/* Incidents */}
        <GlassPanel>
          <h3 className={s.sectionTitle}>INCIDENTS</h3>
          {incidents.length === 0 ? (
            <div className={s.emptyState}>No incidents</div>
          ) : incidents.slice(0, 8).map(inc => (
            <div key={inc.incident_id} className={s.incidentItem}>
              <div className={s.incidentHeader}>
                <span className={s.incidentComponent}>{inc.component}</span>
                <span className={s.incidentStatus} style={{ color: inc.resolution_status === 'open' ? T.red : T.green }}>
                  {inc.resolution_status?.toUpperCase()}
                </span>
              </div>
              <div className={s.incidentDesc}>{inc.description?.slice(0, 60)}</div>
            </div>
          ))}
        </GlassPanel>
      </div>
    </div>
  );
}
